10	export function getDb(): Database {
11	  if (_db) return _db;
12	  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
13	  _db = new Database(DB_PATH);
14	  _db.run("PRAGMA journal_mode = WAL");
15	  _db.run("PRAGMA foreign_keys = ON");
16	  initSchema(_db);
17	  return _db;
18	}
