61	      agent_output_excerpt TEXT,
62	      failure_reason TEXT,
63	      trace TEXT,
64	      agent_output TEXT,
65	      scenario_name TEXT,
66	      scenario_type TEXT,
67	      category TEXT,
68	      UNIQUE(run_id, agent, scenario_id, trial_index)
69	    )
70	  `);
71	
72	  db.run(`
73	    CREATE TABLE IF NOT EXISTS agent_summaries (
74	      run_id TEXT NOT NULL REFERENCES eval_runs(run_id),
75	      agent TEXT NOT NULL,
76	      pass_count INTEGER,
77	      partial_count INTEGER,
78	      fail_count INTEGER,
79	      pass_rate REAL,
80	      avg_confidence_stated REAL,
81	      calibration_gap REAL,
82	      PRIMARY KEY (run_id, agent)
83	    )
84	  `);
85	
86	  db.run(`INSERT OR IGNORE INTO schema_version (version) VALUES (1)`);
87	}
